<template>
  <div>
    <div class="page-head"><div><h2 class="page-title">摄像头识别</h2><p class="page-subtitle">实时画面截帧分析</p></div></div>
    <div class="grid-two"><section class="panel camera-panel"><video ref="video" autoplay playsinline muted></video><canvas ref="canvas"></canvas><div class="actions"><button class="button secondary" @click="openCamera" :disabled="streaming">打开摄像头</button><button class="button" @click="capture" :disabled="!streaming||loading">{{ loading?'识别中...':'识别当前画面' }}</button><button class="button secondary" @click="openWarning" :disabled="!canCapture">发布预警</button><button class="button secondary" @click="stopCamera" :disabled="!streaming">停止</button></div><p v-if="message" class="success-text">{{ message }}</p><p class="error-text">{{ error }}</p></section><result-panel :result="result" media-type="image"/></div>
    <warning-capture-modal :visible="warningVisible" source-type="camera" :result="result" @saved="onWarningSaved" @close="closeWarning"/>
  </div>
</template>
<script>import ResultPanel from "../components/ResultPanel.vue";import WarningCaptureModal from "../components/WarningCaptureModal.vue";export default {name:"CameraDetect",components:{ResultPanel,WarningCaptureModal},data(){return{stream:null,streaming:false,loading:false,error:"",message:"",warningVisible:false,resumeCameraAfterWarning:false,result:null}},computed:{canCapture(){return!this.loading&&!!(this.result&&this.result.id)}},beforeDestroy(){this.stopCamera()},methods:{async openCamera(){this.error="";try{this.stream=await navigator.mediaDevices.getUserMedia({video:true,audio:false});this.$refs.video.srcObject=this.stream;this.streaming=true}catch(e){this.error="摄像头不可用，请检查权限"}},stopCamera(){if(this.stream){this.stream.getTracks().forEach(t=>t.stop())}this.stream=null;this.streaming=false},capture(){const v=this.$refs.video,c=this.$refs.canvas;c.width=v.videoWidth||1280;c.height=v.videoHeight||720;const ctx=c.getContext("2d");ctx.drawImage(v,0,0,c.width,c.height);c.toBlob(async blob=>{if(!blob)return;this.loading=true;this.error="";this.message="";const f=new FormData();f.append("file",blob,"camera.jpg");f.append("source_type","camera");f.append("conf","0.25");try{this.result=await this.$api.upload("/api/detect/image",f)}catch(e){this.error=e.message}finally{this.loading=false}},"image/jpeg",0.92)},openWarning(){if(!this.canCapture)return;const v=this.$refs.video;if(v&&this.streaming)v.pause();this.warningVisible=true},closeWarning(){this.warningVisible=false},onWarningSaved(){this.message="已加入预警提示列表"}}};</script>
<style scoped>.camera-panel{padding:20px}video{width:100%;min-height:280px;background:#0f172a;border-radius:10px;display:block}canvas{display:none}.actions{display:flex;flex-wrap:wrap;gap:10px;margin-top:14px}.success-text{color:#16a34a;min-height:20px;margin-top:10px;font-weight:600}</style>